                <svg width="18" height="10" viewBox="0 0 18 10" xmlns="http://www.w3.org/2000/svg"><g fill="none" fill-rule="evenodd"><path d="M-1-5h20v20H-1z"/><path d="M16.917 8.75c.23 0 .416.187.416.417v.416c0 .23-.186.417-.416.417H1.083a.417.417 0 01-.416-.417v-.416c0-.23.186-.417.416-.417h15.834zm0-4.375c.23 0 .416.187.416.417v.416c0 .23-.186.417-.416.417H1.083a.417.417 0 01-.416-.417v-.416c0-.23.186-.417.416-.417h15.834zm0-4.375c.23 0 .416.187.416.417v.416c0 .23-.186.417-.416.417H1.083A.417.417 0 01.667.833V.417C.667.187.853 0 1.083 0h15.834z" fill="#4C4D4E" fill-rule="nonzero"/></g></svg>
